# Debrief Strategy between rounds

def debrief(previous_round, next_round_type):
    signals_hit = evaluate_signals(previous_round)
    signals_missed = expected_signals(next_round_type) - signals_hit

    if "coding" in previous_round.type:
        if previous_round.felt_difficult:
            adjust("slow down, explain approach first")
        else:
            adjust("maintain pace")

    if "system_design" in previous_round.type and signals_missed.contains("tradeoffs"):
        prepare("lead with tradeoff analysis in next system design round")

    if "behavioral" in previous_round.type and signals_missed.contains("impact"):
        review("top 3 STAR stories with $ impact numbers")
    elif "behavioral" in previous_round.type and signals_missed.contains("scope"):
        review("stories showing org-wide influence")

    return {
        "energy_adjustment": "+10% energy" if previous_round.felt_low_energy else "maintain",
        "focus": f"hit {signals_missed} signals",
        "mindset": "independent round — previous does not affect this one"
    }
